#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;int dp[N],h[N],deq[N],H,T;
inline double Cnt(int i,int j){return 1.0*(dp[i]+h[i]*h[i]-dp[j]-h[j]*h[j])/(h[i]-h[j]);}
signed main()
{
	int n=read(),C=read();rep(1,n,i)h[i]=read();
	deq[H=T=1]=1;dp[1]=0;rep(2,n,i)
	{
		while(H<T&&Cnt(deq[H],deq[H+1])<2.0*h[i])H++;
		dp[i]=dp[deq[H]]+(h[i]-h[deq[H]])*(h[i]-h[deq[H]])+C;
		while(H<T&&Cnt(deq[T],deq[T-1])>Cnt(deq[T],i))--T;deq[++T]=i;
//		printf("%lld :: ",i);rep(H,T,i)printf("%lld ",deq[i]);puts("");
//		printf("%.2lf",Cnt(1,2));
	}
//	rep(1,n,i)printf("%lld ",dp[i]);puts("");
	printf("%lld\n",dp[n]);return 0; 
}
